  function pip(lon, lat, p) {
    let inside = false;
    for (let i = 0, j = p.length - 1; i < p.length; j = i++) {
      const xi = p[i][0], yi = p[i][1], xj = p[j][0], yj = p[j][1];
      if (((yi > lat) !== (yj > lat)) && lon < ((xj - xi) * (lat - yi)) / (yj - yi) + xi) inside = !inside;
    }
    return inside;
  }
  WP.inBasin = function (lon, lat) { return pip(lon, lat, WP.BASIN); };
  // isLand = tropical field mask (forest/temp clip) — not the full continent
  WP.isLand = function (lon, lat) { for (const r of WP.FIELD_LAND) if (pip(lon, lat, r)) return true; return false; };
